const body = $json.body || $json;
const required = ['event', 'coordinator', 'budget', 'logistics'];
const missing = required.filter(function(k) {
  return !body[k] || typeof body[k] !== 'object';
});
if (missing.length > 0) {
  throw new Error('Missing required sections: ' + missing.join(', '));
}
const coord = body.coordinator || {};
if (!coord.name || !coord.email || !coord.phone) {
  throw new Error('Missing coordinator name, email, or phone');
}
const emailParts = coord.email.split('@');
if (emailParts.length !== 2 || !emailParts[1].includes('.')) {
  throw new Error('Invalid coordinator email');
}
const phoneDigits = String(coord.phone).replace(/\D/g, '');
if (phoneDigits.length < 10) {
  throw new Error('Invalid phone number');
}
const eventDate = new Date(body.event.date + 'T12:00:00');
const today = new Date();
today.setHours(0,0,0,0);
if (eventDate < today) {
  throw new Error('Event date must be in the future');
}
const leadId = 'UDC-' + new Date().toISOString().slice(0,10).replace(/-/g,'') + '-' + Math.floor(Math.random() * 900 + 100);
const normalized = {
  lead_id: leadId,
  lead_source: body.lead_source || 'catering-web-v1',
  timestamp: body.timestamp || new Date().toISOString(),
  event: body.event,
  logistics: body.logistics,
  budget: body.budget,
  coordinator: body.coordinator,
  food: body.food || {},
  meta: body.meta || {}
};
return [{ json: normalized }];

const lead = $json;
const evt = lead.event || {};
const log = lead.logistics || {};
const bud = lead.budget || {};
const food = lead.food || {};

const headcount = parseInt(log.headcount) || 0;
let headcountScore = 0;
if (headcount >= 250) headcountScore = 20;
else if (headcount >= 150) headcountScore = 18;
else if (headcount >= 100) headcountScore = 15;
else if (headcount >= 60) headcountScore = 12;
else if (headcount >= 40) headcountScore = 10;
else if (headcount >= 20) headcountScore = 7;
else if (headcount >= 10) headcountScore = 5;

const budgetMap = {
  'lt300': 200, '300-600': 450, '600-1200': 900,
  '1200-2500': 1850, 'gt2500': 3000, 'quote': 0
};
const budgetVal = budgetMap[bud.range] || 0;
const budgetPerPerson = headcount > 0 ? budgetVal / headcount : 0;
let budgetScore = 0;
if (budgetPerPerson >= 15) budgetScore = 20;
else if (budgetPerPerson >= 10) budgetScore = 15;
else if (budgetPerPerson >= 7) budgetScore = 10;
else if (budgetPerPerson >= 5) budgetScore = 5;
else if (budgetVal > 0) budgetScore = 2;

const eventDate = new Date(evt.date + 'T12:00:00');
const today = new Date();
const daysUntil = Math.ceil((eventDate - today) / (1000 * 60 * 60 * 24));
let leadTimeScore = 0;
if (daysUntil >= 28) leadTimeScore = 20;
else if (daysUntil >= 14) leadTimeScore = 15;
else if (daysUntil >= 7) leadTimeScore = 10;
else if (daysUntil >= 3) leadTimeScore = 5;

const setupMinutes = parseInt(evt.setup_minutes_before) || 0;
const serviceStyle = log.service_style || 'drop-off';
let setupScore = 0;
if (serviceStyle === 'drop-off' && setupMinutes <= 15) setupScore = 15;
else if (serviceStyle === 'drop-off') setupScore = 12;
else if (serviceStyle === 'staffed-buffet') setupScore = 10;
else if (serviceStyle === 'plated') setupScore = 5;
else setupScore = 8;

const distanceMap = { 'lt5': 10, '5-15': 7, '15-30': 4, 'gt30': 0, 'unknown': 5 };
const distanceScore = distanceMap[log.venue_distance] || 5;

const paymentMap = { 'upfront': 10, '50-50': 8, 'day-of': 5, 'net30': 3 };
const paymentScore = paymentMap[bud.payment_timing] || 0;

const restrictions = Array.isArray(food.dietary_restrictions) ? food.dietary_restrictions : [];
const hasNone = restrictions.indexOf('none') >= 0;
const activeRestrictions = hasNone ? 0 : restrictions.length;
let dietaryScore = 0;
if (activeRestrictions === 0) dietaryScore = 5;
else if (activeRestrictions <= 2) dietaryScore = 3;
else dietaryScore = 0;

let bonus = 0;
if (bud.who_pays === 'company') bonus += 5;
if (daysUntil >= 14) bonus += 3;

let penalty = 0;
if (daysUntil < 3) penalty += 20;
if (headcount < 10) penalty += 15;
if (log.venue_distance === 'gt30' && bud.range === 'quote') penalty += 10;

const rawScore = headcountScore + budgetScore + leadTimeScore + setupScore + distanceScore + paymentScore + dietaryScore + bonus;
const finalScore = Math.max(0, Math.min(100, rawScore - penalty));

let tier, action;
if (finalScore >= 70) {
  tier = 'ACCEPT';
  action = 'AUTO-ACCEPT';
} else if (finalScore >= 40) {
  tier = 'REVIEW';
  action = 'NEEDS-REVIEW';
} else {
  tier = 'REJECT';
  action = 'AUTO-REJECT';
}

const wasPenalized = penalty > 0 && (rawScore - penalty) < 40;

const scored = {
  lead_id: lead.lead_id,
  lead_source: lead.lead_source,
  timestamp: lead.timestamp,
  score: finalScore,
  tier: tier,
  action: action,
  was_penalized: wasPenalized,
  breakdown: {
    headcount: { value: headcount, raw: headcountScore, max: 20 },
    budget: { value: budgetVal, per_person: Math.round(budgetPerPerson * 100) / 100, raw: budgetScore, max: 20 },
    lead_time: { days: daysUntil, raw: leadTimeScore, max: 20 },
    setup: { style: serviceStyle, minutes: setupMinutes, raw: setupScore, max: 15 },
    distance: { value: log.venue_distance, raw: distanceScore, max: 10 },
    payment: { timing: bud.payment_timing, raw: paymentScore, max: 10 },
    dietary: { restrictions: activeRestrictions, raw: dietaryScore, max: 5 },
    bonus: bonus,
    penalty: penalty
  },
  event: lead.event,
  logistics: lead.logistics,
  budget: lead.budget,
  coordinator: lead.coordinator,
  food: lead.food,
  meta: lead.meta
};

return [{ json: scored }];

try {
  const sqlite3 = require('sqlite3');
  const path = require('path');

  const dbPath = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-catering.db';
  const db = new sqlite3.Database(dbPath);

  const lead = $json;
  const evt = lead.event || {};
  const log = lead.logistics || {};
  const bud = lead.budget || {};
  const coord = lead.coordinator || {};
  const food = lead.food || {};
  const meta = lead.meta || {};

  db.run(`INSERT OR REPLACE INTO catering_leads (
    lead_id, lead_source, event_name, event_type, event_date, event_time,
    duration_hours, setup_minutes, headcount, venue_name, venue_address,
    venue_distance, service_style, equipment_needed, budget_range, budget_value,
    budget_per_person, who_pays, payment_timing, coordinator_name, coordinator_email,
    coordinator_phone, coordinator_role, dietary_restrictions, menu_preferences,
    special_requests, score, tier, action, was_penalized, breakdown, email_sent,
    owner_notified, status, utm_source, referrer
  ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
  [
    lead.lead_id,
    lead.lead_source || 'catering-web-v2',
    evt.name || '',
    evt.type || '',
    evt.date || '',
    evt.time || '',
    parseFloat(evt.duration_hours) || 0,
    parseInt(evt.setup_minutes_before) || 0,
    parseInt(log.headcount) || 0,
    log.venue_name || '',
    log.venue_address || '',
    log.venue_distance || '',
    log.service_style || '',
    Array.isArray(log.equipment_needed) ? log.equipment_needed.join(', ') : '',
    bud.range || '',
    0,
    0,
    bud.who_pays || '',
    bud.payment_timing || '',
    coord.name || '',
    coord.email || '',
    coord.phone || '',
    coord.role || '',
    Array.isArray(food.dietary_restrictions) ? food.dietary_restrictions.join(', ') : '',
    food.menu_preferences || '',
    food.special_requests || '',
    lead.score || 0,
    lead.tier || '',
    lead.action || '',
    lead.was_penalized ? 1 : 0,
    JSON.stringify(lead.breakdown || {}),
    1,
    1,
    lead.tier === 'ACCEPT' ? 'accepted' : lead.tier === 'REVIEW' ? 'review' : 'rejected',
    meta.utm_source || '',
    meta.referrer || ''
  ],
  function(err) {
    if (err) {
      console.error('SQLite error:', err.message);
    }
  });

  db.close();
} catch (e) {
  console.error('Error:', e.message);
}

return [{ json: lead }];

const data = $json || {};
var message;
var tier = data.tier || 'UNKNOWN';
if (tier === 'ACCEPT') {
  message = 'We are available! Check your email for next steps.';
} else if (tier === 'REVIEW') {
  message = 'We need a few more details. Check your email.';
} else if (tier === 'REJECT') {
  message = 'We reviewed your request. Check your email for details.';
} else {
  message = 'Thank you for your catering request. We will review it and email you shortly.';
}
return [{
  json: {
    success: true,
    lead_id: data.lead_id || null,
    tier: tier,
    score: data.score || null,
    message: message
  }
}];
